import pandas as pd
import numpy as np
from typing import List, Dict

# --- Analysis Logic based on Reference Code Cells [0, 1, 4, 5, 6, 30] ---

# Global variables and configuration
_YEARS = [2021, 2022]
_COUNTRIES = ["Japan", "United States of America", "China", "India"]

# File paths - restored to absolute paths from dataset_paths
_FILEPATHS = {
    2021: "kaggle_survey_2021/source/kaggle_survey_2021_responses.csv",
    2022: "/Kaggle/analyze_code/251204_communities/da_filter_communities/community_24/kaggle-survey-2018/notebooks/how-is-japan-doing/private_dataset/kaggle_survey_2022/kaggle_survey_2022_responses.csv"
}

# Big Mac prices provided in the question
bigmac_price = {
    "Japan": {
        2022: 4.33,
        2021: 4.52,
    },
    "United States of America": {
        2022: 4.55,
        2021: 4.76,
    },
    "China": {
        2022: 3.64,
        2021: 3.53,
    },
    "India": {
        2022: 3.42,
        2021: 3.22,
    },
}

# --- Data Loading and Cleaning Functions (Cell 4) ---

def keep_employees_in_2022df(df: pd.DataFrame) -> pd.DataFrame:
    df = df[df["Q5"] == "No"]
    df = df[~df["Q23"].str.contains("not employed", case=False, na=False)]
    return df

def keep_employees_in_2019_to_2021df(df: pd.DataFrame) -> pd.DataFrame:
    df = df[~df["Q5"].str.contains("Student", case=False, na=False)]
    df = df[~df["Q5"].str.contains("employed", case=False, na=False)]
    return df

def keep_employees_in_df(df: pd.DataFrame, year: int) -> pd.DataFrame:
    if year == 2022:
        return keep_employees_in_2022df(df)
    elif year == 2021:
        return keep_employees_in_2019_to_2021df(df)
    return df

def filter_country_in_df(df: pd.DataFrame, year: int, country: str) -> pd.DataFrame:
    if year == 2022:
        return df[df["Q4"] == country]
    elif year == 2021:
        return df[df["Q3"] == country]
    return df

def read_year_country_data(filepath: str, year: int, country: str) -> pd.DataFrame:
    df = pd.read_csv(filepath, dtype=str, low_memory=False)
    df = filter_country_in_df(df, year, country)
    df = keep_employees_in_df(df, year)
    return df

# --- Salary Processing Functions (Cell 5) ---

def convert_salary_to_num_bigmacs(salary_data: pd.Series, year: int, country: str) -> pd.Series:
    return salary_data // bigmac_price[country][year]

def convert_str_range_to_median(str_range: str) -> float:
    if not pd.isnull(str_range):
        str_range = str(str_range)
        str_range = str_range.replace(",", "").replace("$", "").replace(">", "").replace("+", "").replace(" ", "")
        if "-" in str_range:
            index = str_range.find("-")
            try:
                smallest = float(str_range[:index])
                largest = float(str_range[(index+1):])
                return (largest + smallest)/2
            except ValueError:
                return np.nan
        else:
            try:
                return float(str_range)
            except ValueError:
                return np.nan
    return np.nan

def process_salary_data(salary_data: pd.Series, year: int, country: str) -> pd.Series:
    salary_data = salary_data.apply(convert_str_range_to_median)
    return convert_salary_to_num_bigmacs(salary_data, year, country)

def get_salary_data(df: pd.DataFrame, year: int, country: str) -> pd.Series:
    salary_data_select = {2022: "Q29", 2021: "Q25"}
    col_name = salary_data_select[year]
    salary_data = df[col_name].copy()
    salary_data = salary_data.replace("I do not wish to disclose my approximate yearly compensation", np.nan)
    return process_salary_data(salary_data, year, country)

# --- Main Processing Logic ---

target_countries = ["United States of America", "China", "India", "Japan"]
country_stats = {}

for country in target_countries:
    country_stats[country] = {}
    for year in _YEARS:
        filepath = _FILEPATHS[year]
        df = read_year_country_data(filepath, year, country)
        salary_series = get_salary_data(df, year, country)
        country_stats[country][year] = salary_series.mean()

output_values = []
for country in target_countries:
    avg_2021 = country_stats[country][2021]
    avg_2022 = country_stats[country][2022]
    if pd.notna(avg_2021) and pd.notna(avg_2022) and avg_2021 != 0:
        pct_increase = ((avg_2022 - avg_2021) / avg_2021) * 100
        output_values.append(f"{pct_increase:.2f}%")
    else:
        output_values.append("Not Applicable")

print("; ".join(output_values))
